SELECT COUNT(*) AS active_payment_methods
FROM payment_methods
WHERE status = 'active';

SELECT COUNT(DISTINCT customer_id) AS num_customers_with_active_payment_methods
FROM payment_methods
WHERE status = 'active';

SELECT ssn
FROM customers
WHERE customer_id NOT IN (
  SELECT customer_id
  FROM payment_methods
);

SELECT MAX(credit_limit) 
FROM payment_methods 
WHERE customer_id = 1;
